dataSet.query:
ВЫБРАТЬ РАЗРЕШЕННЫЕ
	Рег.Фирма КАК Фирма,
	Рег.Склад КАК Склад,
	Рег.Номенклатура КАК Номенклатура,
	Рег.Партия КАК Партия,
	Рег.Партия.Серия КАК ПартияСерия,    
	Рег.Партия.Док.ВКД_Инвойс КАК Инвойс,
	Рег.Партия.Контрагент КАК ПартияКонтрагент,
	Рег.Партия.Валюта КАК ПартияВалюта,
	ВЫБОР
		КОГДА &СкрытьЦены
			ТОГДА NULL
		ИНАЧЕ 
			ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0)
	КОНЕЦ КАК ПартияЦенаЗакупки,
	Рег.Партия.ДатаПартии КАК ПартияДатаПартии,
	НАЧАЛОПЕРИОДА(Рег.Партия.ДатаПартии, МЕСЯЦ) КАК МесяцПрихода,
	Рег.ОстатокНачальныйОстаток КАК ОстатокНачальныйОстаток,
	Рег.ОстатокПриход КАК ОстатокПриход,
	Рег.ОстатокРасход КАК ОстатокРасход,
	Рег.ОстатокКонечныйОстаток КАК ОстатокКонечныйОстаток,
	ВЫРАЗИТЬ(Рег.ОстатокНачальныйОстаток * 
			//ВЫБОР
			//КОГДА ЕСТЬNULL(Рег.Партия.ВКД_ЦенаСЗатратами, 0) = 0
			//	ТОГДА ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0)
			//ИНАЧЕ ЕСТЬNULL(Рег.Партия.ВКД_ЦенаСЗатратами, 0)
			//КОНЕЦ 
		ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0)
		КАК ЧИСЛО(19, 2)) КАК НачСуммаВал,
	ВЫРАЗИТЬ(Рег.ОстатокПриход * 
			//ВЫБОР
			//КОГДА ЕСТЬNULL(Рег.Партия.ВКД_ЦенаСЗатратами, 0) = 0
			//	ТОГДА ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0)
			//ИНАЧЕ ЕСТЬNULL(Рег.Партия.ВКД_ЦенаСЗатратами, 0)
			//КОНЕЦ
			ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0) 
		КАК ЧИСЛО(19, 2)) КАК ПриСуммаВал,
	ВЫРАЗИТЬ(Рег.ОстатокРасход * 
			//ВЫБОР
			//КОГДА ЕСТЬNULL(Рег.Партия.ВКД_ЦенаСЗатратами, 0) = 0
			//	ТОГДА ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0)
			//ИНАЧЕ ЕСТЬNULL(Рег.Партия.ВКД_ЦенаСЗатратами, 0)
			//КОНЕЦ 
		    ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0)
		КАК ЧИСЛО(19, 2)) КАК РасСуммаВал,
	ВЫРАЗИТЬ(Рег.ОстатокКонечныйОстаток * 
			//ВЫБОР
			//КОГДА ЕСТЬNULL(Рег.Партия.ВКД_ЦенаСЗатратами, 0) = 0
			//	ТОГДА ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0)
			//ИНАЧЕ ЕСТЬNULL(Рег.Партия.ВКД_ЦенаСЗатратами, 0)
			//КОНЕЦ  
			ЕСТЬNULL(Рег.Партия.ЦенаЗакупки, 0)
		КАК ЧИСЛО(19, 2)) КАК КонСуммаВал,
	Рег.Регистратор КАК Регистратор,
	Рег.ПериодСекунда КАК ПериодСекунда
ИЗ
	РегистрНакопления.ОстаткиТовара.ОстаткиИОбороты(, , Авто, , Номенклатура.ТипНоменклатуры = Значение(Перечисление.ТипыНоменклатуры.Товар) {(Склад В (&Склады))}) КАК Рег
